import{_ as h,o as n,c as i,ae as a}from"./chunks/framework.BeVX27ge.js";const s=JSON.parse('{"title":"Trợ lý Kiến thức","description":"","frontmatter":{},"headers":[],"relativePath":"knowledge-assistant.md","filePath":"knowledge-assistant.md"}'),c={name:"knowledge-assistant.md"};function u(l,t,o,r,e,d){return n(),i("div",null,[...t[0]||(t[0]=[a('<h1 id="tro-ly-kien-thuc" tabindex="-1">Trợ lý Kiến thức <a class="header-anchor" href="#tro-ly-kien-thuc" aria-label="Permalink to &quot;Trợ lý Kiến thức&quot;">​</a></h1><blockquote><p>Tra cứu kiến thức bán hàng bất cứ lúc nào, hỗ trợ chuyên nghiệp cho việc luyện tập của bạn.</p></blockquote><h2 id="tong-quan" tabindex="-1">Tổng quan <a class="header-anchor" href="#tong-quan" aria-label="Permalink to &quot;Tổng quan&quot;">​</a></h2><p>Trợ lý Kiến thức là tính năng Hỏi &amp; Đáp thông minh được tích hợp trong AI Coach, dựa trên công nghệ RAG. Nó có thể truy xuất thông tin liên quan từ cơ sở kiến thức của công ty và tạo ra câu trả lời chính xác. Bạn có thể sử dụng bất cứ lúc nào: trước, trong và sau khi thực hành.</p><h2 id="cach-mo" tabindex="-1">Cách Mở <a class="header-anchor" href="#cach-mo" aria-label="Permalink to &quot;Cách Mở&quot;">​</a></h2><p>Nhấp vào <strong>Biểu tượng Trợ lý Kiến thức</strong> trên thanh điều hướng góc trên cùng bên phải.</p><blockquote><p>Tính năng này yêu cầu quyền đọc cơ sở kiến thức. Nếu bạn không thấy biểu tượng, vui lòng liên hệ quản trị viên.</p></blockquote><hr><h2 id="giao-dien" tabindex="-1">Giao diện <a class="header-anchor" href="#giao-dien" aria-label="Permalink to &quot;Giao diện&quot;">​</a></h2><h3 id="thanh-tieu-đe" tabindex="-1">Thanh Tiêu đề <a class="header-anchor" href="#thanh-tieu-đe" aria-label="Permalink to &quot;Thanh Tiêu đề&quot;">​</a></h3><ul><li><strong>AI Logo</strong>: Biểu tượng nhận diện của Trợ lý Kiến thức</li><li><strong>AI Chat</strong>: Văn bản tiêu đề</li><li><strong>Trạng thái</strong>: Chấm xanh lá cây chỉ &quot;Trực tuyến&quot;; đỏ chỉ &quot;Ngoại tuyến&quot;</li><li><strong>Xóa cuộc trò chuyện</strong>: Xóa tất cả lịch sử trò chuyện và bắt đầu lại</li></ul><h3 id="khu-vuc-tro-chuyen" tabindex="-1">Khu vực Trò chuyện <a class="header-anchor" href="#khu-vuc-tro-chuyen" aria-label="Permalink to &quot;Khu vực Trò chuyện&quot;">​</a></h3><ul><li><strong>Màn hình chào mừng</strong>: Hiển thị lần đầu mở, cung cấp hướng dẫn</li><li><strong>Danh sách Tin nhắn</strong>: Câu hỏi của bạn (phải) và phản hồi của AI (trái)</li><li><strong>Chỉ báo đang gõ</strong>: Hiệu ứng động khi AI đang tạo câu trả lời</li></ul><h3 id="khu-vuc-nhap-lieu" tabindex="-1">Khu vực Nhập liệu <a class="header-anchor" href="#khu-vuc-nhap-lieu" aria-label="Permalink to &quot;Khu vực Nhập liệu&quot;">​</a></h3><ul><li>Hộp nhập: Nhập câu hỏi bạn muốn tra cứu</li><li>Nút gửi: Nhấp để gửi câu hỏi (tạm thời vô hiệu hóa khi AI đang trả lời)</li></ul><hr><h2 id="cach-su-dung" tabindex="-1">Cách Sử dụng <a class="header-anchor" href="#cach-su-dung" aria-label="Permalink to &quot;Cách Sử dụng&quot;">​</a></h2><ol><li>Nhấp vào biểu tượng Trợ lý Kiến thức để mở cửa sổ trò chuyện.</li><li>Nhập câu hỏi của bạn.</li><li>Nhấp Gửi hoặc nhấn Enter.</li><li>Đợi AI truy xuất dữ liệu từ cơ sở kiến thức và trả lời.</li><li>Xem nội dung và tiếp tục đặt câu hỏi nếu cần.</li></ol><h2 id="tinh-huong-su-dung" tabindex="-1">Tình huống Sử dụng <a class="header-anchor" href="#tinh-huong-su-dung" aria-label="Permalink to &quot;Tình huống Sử dụng&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tình huống</th><th>Ví dụ Câu hỏi</th></tr></thead><tbody><tr><td>Tra cứu Sản phẩm</td><td>&quot;Phạm vi bảo hiểm của Sản phẩm XX là gì?&quot;</td></tr><tr><td>Tham khảo Kịch bản</td><td>&quot;Làm sao để thuyết phục khách hàng lo ngại phí bảo hiểm cao?&quot;</td></tr><tr><td>Tra cứu Quy định</td><td>&quot;Quy trình yêu cầu bồi thường là gì?&quot;</td></tr><tr><td>So sánh Phân tích</td><td>&quot;Sự khác biệt giữa Gói A và Gói B là gì?&quot;</td></tr><tr><td>C.Hỏi Thường gặp</td><td>&quot;3 câu hỏi phổ biến nhất của khách hàng là gì?&quot;</td></tr></tbody></table><h2 id="luu-y" tabindex="-1">Lưu ý <a class="header-anchor" href="#luu-y" aria-label="Permalink to &quot;Lưu ý&quot;">​</a></h2><ul><li>Chất lượng câu trả lời phụ thuộc vào cơ sở kiến thức do quản trị viên tải lên.</li><li>Câu trả lời chỉ mang tính tham khảo. Hãy dựa vào tài liệu chính thức của công ty trong thực tế.</li><li>Lịch sử trò chuyện được lưu trên trình duyệt cục bộ.</li><li>Chuyển đổi tài khoản sẽ xóa lịch sử.</li></ul><hr><h2 id="buoc-tiep-theo" tabindex="-1">Bước tiếp theo <a class="header-anchor" href="#buoc-tiep-theo" aria-label="Permalink to &quot;Bước tiếp theo&quot;">​</a></h2><ul><li>Bắt đầu <a href="./practice.html">Thực hành</a> để áp dụng kiến thức</li><li>Xem <a href="./evaluation.html">Báo cáo Đánh giá</a> để tìm ra điểm cần cải thiện</li></ul>',25)])])}const b=h(c,[["render",u]]);export{s as __pageData,b as default};
